solutionCode:
function buildTransfer(fromPubkey, toPubkey, lamports) {
  return {
    programId: "11111111111111111111111111111111",
    from: fromPubkey.toBase58(),
    to: toPubkey.toBase58(),
    lamports,
  };
}

testCode:
const { PublicKey } = require("@solana/web3.js");

const from = new PublicKey("So11111111111111111111111111111111111111112");
const to = new PublicKey("TokenzQdBNbLqP5VEhdkAS6EPFLC1PHnBqCXEpPxuEb");
const result = buildTransfer(from, to, 5000);

assert(result.lamports === 5000, "lamports should be 5000");
assert(result.from === from.toBase58(), "from pubkey mismatch");
assert(result.to === to.toBase58(), "to pubkey mismatch");
assert(result.programId === "11111111111111111111111111111111", "programId should be System Program");
